1	from fastapi import FastAPI
2	from fastapi.responses import JSONResponse
3	from fastapi.testclient import TestClient
4	from inline_snapshot import snapshot
5	from pydantic import BaseModel
6	
7	app = FastAPI()
8	
9	
10	class Item(BaseModel):
11	    name: str
12	    price: float | None = None
13	
14	
15	@app.api_route("/items/{item_id}", methods=["GET"])
16	def get_items(item_id: str):
17	    return {"item_id": item_id}
18	
19	
20	def get_not_decorated(item_id: str):
21	    return {"item_id": item_id}
22	
23	
24	app.add_api_route("/items-not-decorated/{item_id}", get_not_decorated)
25	
26	
27	@app.delete("/items/{item_id}")
28	def delete_item(item_id: str, item: Item):
29	    return {"item_id": item_id, "item": item}
30	
31	
32	@app.head("/items/{item_id}")
33	def head_item(item_id: str):
34	    return JSONResponse(None, headers={"x-fastapi-item-id": item_id})
35	
36	
37	@app.options("/items/{item_id}")
38	def options_item(item_id: str):
39	    return JSONResponse(None, headers={"x-fastapi-item-id": item_id})
40	
41	
42	@app.patch("/items/{item_id}")
43	def patch_item(item_id: str, item: Item):
44	    return {"item_id": item_id, "item": item}
45	
46	
47	@app.trace("/items/{item_id}")
48	def trace_item(item_id: str):
49	    return JSONResponse(None, media_type="message/http")
50	
51	
52	client = TestClient(app)
53	
54	
55	def test_get_api_route():
56	    response = client.get("/items/foo")
57	    assert response.status_code == 200, response.text
58	    assert response.json() == {"item_id": "foo"}
59	
60	
61	def test_get_api_route_not_decorated():
62	    response = client.get("/items-not-decorated/foo")
63	    assert response.status_code == 200, response.text
64	    assert response.json() == {"item_id": "foo"}
65	
66	
67	def test_delete():
68	    response = client.request("DELETE", "/items/foo", json={"name": "Foo"})
69	    assert response.status_code == 200, response.text
70	    assert response.json() == {"item_id": "foo", "item": {"name": "Foo", "price": None}}
71	
72	
73	def test_head():
74	    response = client.head("/items/foo")
75	    assert response.status_code == 200, response.text
76	    assert response.headers["x-fastapi-item-id"] == "foo"
77	
78	
79	def test_options():
80	    response = client.options("/items/foo")
81	    assert response.status_code == 200, response.text
82	    assert response.headers["x-fastapi-item-id"] == "foo"
83	
84	
85	def test_patch():
86	    response = client.patch("/items/foo", json={"name": "Foo"})
87	    assert response.status_code == 200, response.text
88	    assert response.json() == {"item_id": "foo", "item": {"name": "Foo", "price": None}}
89	
90	
91	def test_trace():
92	    response = client.request("trace", "/items/foo")
93	    assert response.status_code == 200, response.text
94	    assert response.headers["content-type"] == "message/http"
